import React from "react";
import { PageShell } from "@ui/containers/PageShell";
import { Section } from "@ui/containers/Section";
import { Card } from "@ui/molecules/Card";
import { ErrorState } from "@ui/containers/ErrorState";

interface WIPPageProps {
  moduleId: string;
  routeBase: string;
}

export default function WIPPage({ moduleId, routeBase }: WIPPageProps) {
  return (
    <PageShell title="En construcción">
      <Section>
        <Card>
          <ErrorState
            title="En construcción"
            description="Este módulo está planeado para el Cartucho, aún no implementado."
            icon="code"
          />
          <div style={{ marginTop: '24px', textAlign: 'center', opacity: 0.5, fontSize: '12px', fontFamily: 'monospace' }}>
            ID: {moduleId} | Route: {routeBase}
          </div>
        </Card>
      </Section>
    </PageShell>
  );
}
